.darma-loader-darma-custom-061 {
  --s: 25px;

  --_d: calc(0.353*var(--s));
  width: calc(var(--s) + var(--_d));
  aspect-ratio: 1;
  display: flex;
}
.darma-loader-darma-custom-061:before,
.darma-loader-darma-custom-061:after {
  content: "";
  flex: 1;
  clip-path: polygon(var(--_d) 0,100% 0,100% calc(100% - var(--_d)),calc(100% - var(--_d)) 100%,0 100%,0 var(--_d));
  background:
    conic-gradient(from -90deg at calc(100% - var(--_d)) var(--_d),
     #fff 135deg,#666 0 270deg,#aaa 0);
  animation: darma-loader-darma-custom-061-l5 1.2s infinite;
}
.darma-loader-darma-custom-061:before {
  margin-right: calc(var(--_d)/-2 - 1px);
}
.darma-loader-darma-custom-061:after {
  margin-left: calc(var(--_d)/-2 - 1px);
  animation-delay: 0.6s
}
@keyframes darma-loader-darma-custom-061-l5{
  0%     {transform: translateY(0)}
  16.67% {transform: translateY(-10px)}
  33.33% {transform: translateY(10px)}
  50%,
  100%   {transform: translateY(0)}
}

